function media(title: string, cueA: string, cueB: string, accent: string, shape: 'leaf' | 'instrument' | 'plant' | 'book' | 'portrait' | 'fruit' | 'country' | 'city' | 'ruin' | 'part' | 'building' | 'tool' | 'kitchen' | 'dog' | 'cat' | 'sign' | 'pasta' | 'cloud' | 'flag' | 'spice' | 'cheese' | 'art' | 'camera' | 'notation' | 'sports' | 'lab' | 'insect' | 'mushroom' | 'constellation' | 'gem'): QuestionMedia[] {
  return [
    {
      type: 'image',
      src: clueSvg(title, cueA, cueB, accent, shape),
      alt: `Stylized identification clue for ${title}.`,
      label: 'Cute clue',
      caption: 'A playful clue card for the thing.',
    },
    {
      type: 'image',
      src: clueSvg('field clue', cueA, cueB, '#5d6d7e', shape),
      alt: `More literal clue card for ${title}.`,
      label: 'Literal clue',
      caption: 'Use the traits, context, and function before guessing.',
    },
  ]
}

function q(
  id: number,
  chapter: string,
  title: string,
  prompt: string,
  correct: string,
  wrongLabels: string[],
  lesson: string,
  difficulty: BonusDifficulty,
  clue: QuestionMedia[],
): Question {
  const wrong = wrongLabels.slice(0, 3).map((label): [string, string, string] => [
    label,
    `${label} is a plausible distractor, but it does not match the key clue in this prompt.`,
    'Use the most specific trait, role, or context clue.',
  ])

  return {
    ...makeSimpleQuestion(id, 'Fun', chapter, title, prompt, correct, wrong, lesson, source),
    difficulty,
    media: clue,
  }
}

